items.signature:
VkResult vkInitializePerformanceApiINTEL(
 VkDevice device,
 const VkInitializePerformanceApiInfoINTEL* pInitializeInfo);

items.example:
VkDevice device = VK_NULL_HANDLE;
VkInitializePerformanceApiInfoINTEL initializeInfo = {};
initializeInfo.sType = VK_STRUCTURE_TYPE_INITIALIZE_PERFORMANCE_API_INFO_INTEL;

VkResult result = vkInitializePerformanceApiINTEL(
    device,
    &initializeInfo
);

if (result == VK_SUCCESS) {
    // تمت العملية بنجاح ويمكن متابعة العمل بعد vkInitializePerformanceApiINTEL
} else {
    // عالج رمز الخطأ أو أعد تهيئة الموارد المطلوبة
}

